const paginationTable=document.getElementById("paginationTable"),searchKey=document.getElementById("search-event"),filterEl=document.getElementById("list-filter"),dataElement=document.getElementById("pagination-data");if(dataElement){const paginationData=JSON.parse(dataElement.textContent);paginationTable&&(paginationTable.pageSizeOptions=paginationData.pageSizeOptions,paginationTable.totalCount=paginationData.totalCount,paginationTable.pageNumber=paginationData.pageNumber,paginationTable.pageSize=paginationData.pageSize,paginationTable.paginationText=paginationData.paginationText,paginationTable.addEventListener("insPaginationChange",handlePaginationChange))}function handlePaginationChange(event){const{pageNumber:pageNumber,pageSize:pageSize}=event.detail;updateUrlParams({page:pageNumber,per_page:pageSize})}function handleSearch(){updateUrlParams({search:searchKey.value.trim(),page:1})}function updateUrlParams(params){const url=new URL(window.location.href);Object.entries(params).forEach((([key,value])=>{null==value?url.searchParams.delete(key):url.searchParams.set(key,value)})),window.location.href=url.toString()}searchKey&&(searchKey.addEventListener("insIconClick",handleSearch),searchKey.addEventListener("insInput",(e=>{13===e.detail.keyCode&&handleSearch()}))),filterEl&&filterEl.addEventListener("insFilterApply",(event=>{const{Category:Category,Location:Location,"Sort by":sortLabel}=event.detail,updatedParams={};updatedParams.category=Category&&"all"!==Category.toLowerCase()?Category:null,updatedParams.location=Location&&"all"!==Location.toLowerCase()?Location:null,updatedParams.sort=sortLabel||null,updatedParams.page=1,updateUrlParams(updatedParams)}));